code.C:
#include <stdio.h>

int checkIfPowerOfTwo(int n) {
    if (n <= 0) return 0;
    return (n & (n - 1)) == 0;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int x;
        scanf("%d", &x);
        printf("%d\n", checkIfPowerOfTwo(x));
    }
    return 0;
}

