#include <bits/stdc++.h>
using namespace std;

bool checkIfPowerOfTwo(int n) {
    if (n <= 0) return false;
    return (n & (n - 1)) == 0;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int x;
        cin >> x;
        cout << (checkIfPowerOfTwo(x) ? 1 : 0) << '\n';
    }
